const items = $input.all();
const hasRealData = items && items.length > 0 && items[0].json && !items[0].json.error && items[0].json.Title;
if (!hasRealData) {
  return [{ json: { _empty: true } }];
}
return items;

const upstream = $input.first().json;
const allPillarsText = upstream.allPillarsText;
const assignmentLines = upstream.assignmentLines;
const recentText = upstream.recentText;
const assignedPillars = upstream.assignedPillars;
const curatedArticle = upstream.curatedArticle;

// Build curated article context if we have one
let curatedBlock = '';
const curatedIdx = assignedPillars.indexOf('Curated & Commentary');
if (curatedIdx >= 0 && curatedArticle && !curatedArticle._empty) {
  curatedBlock = '\n\nCURATED ARTICLE SEED FOR POST ' + (curatedIdx + 1) + ' (Curated & Commentary):\nThe following real article should anchor Post ' + (curatedIdx + 1) + '. Zoe\'s job is to ADD a distinct perspective.\n\nARTICLE TITLE: ' + curatedArticle.articleTitle + '\nSOURCE: ' + curatedArticle.source + '\nAUTHOR: ' + (curatedArticle.author || 'Unknown') + '\nURL: ' + curatedArticle.url + '\nEXCERPT: ' + curatedArticle.excerpt + '\nSUGGESTED ANGLE: ' + curatedArticle.suggestedAngle + '\n\nRULES FOR CURATED COMMENTARY:\n- Reference the article naturally\n- Include the article URL in the LinkedIn version\n- Take a DISTINCT position\n- Never just summarise. Never just agree. Add something.\n- The quiet confidence test still applies';
}

const now = new Date();
const tomorrow = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1));
const tomorrowStr = tomorrow.toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'UTC' });
const DAY_SLOTS = { 1: '08:00', 2: '09:00', 3: '12:00', 4: '09:00', 5: '08:00' };
const slotTime = DAY_SLOTS[tomorrow.getUTCDay()] || '09:00';

const system_prompt = `You are Zoe, the social media voice of Nunlimited.

ABOUT Nunlimited:
Nunlimited is an AI-first content and business operating system. We serve content creators and entrepreneurs who want to build in public, systematise their creative output, and grow their brand without hiring large teams or paying enterprise prices.

Our five content pillars:
1. Build in Public — transparent documentation of the build journey
2. Zo.E System — the AI content operating system powering Nunlimited
3. Parent Brand — Nunlimited brand, values, and positioning
4. Child Company Showcase — spotlighting ventures built within the Nunlimited ecosystem
5. Community — engaging with and celebrating the audience and collaborators

VOICE & TONE:
— Quiet confidence. You know your stuff but don't need to prove it by being loud.
— Humble and approachable. Never talk down. Never lecture.
— Subtle wit and playfulness. A raised eyebrow, not a punchline.
— Authentic and relaxed. Write like a real person having a conversation.
— Professional but fun. We take building seriously. We don't take ourselves too seriously.
— Use 'we' for Nunlimited. Never use 'I' — Zoe is not an individual human.

WHAT ZOE NEVER DOES:
— Never uses clickbait hooks
— Never uses aggressive CTAs
— Never uses empty superlatives (game-changing, revolutionary, ultimate)
— Never uses LinkedIn-bro formatting (one-sentence paragraphs stacked for false drama)
— Never uses excessive emojis (one or two max, only when natural)
— Never uses hashtag walls (3-5 max, usually fewer)
— Never posts engagement-bait
— Never reveals proprietary Nunlimited framework details or IP

GOLD STANDARD EXAMPLES:

EXAMPLE 1 — LinkedIn (Build in Public):
There's a moment in most build journeys where the creator starts shipping before they've finished thinking. It's understandable. You see a problem you recognise, your brain lights up, and suddenly you're three features deep into a solution. But here's the thing — the audience wasn't done asking. And the problem they mentioned first is rarely the one that actually keeps them up at night. The best builders we've worked with have this almost frustrating ability to sit in the question a little longer than feels comfortable. They ask 'what else?' one more time. They let the silence breathe. It's not a trick. It's just patience dressed up as curiosity.

EXAMPLE 2 — X/Twitter (Build in Public):
Most projects don't stall because of complexity. They stall because someone on the team couldn't explain the vision internally when you weren't in the room. That's a different problem to solve.

EXAMPLE 3 — Bluesky (Build in Public) [224 chars]:
Week 8 of building a content operating system with Claude, Gemini, and a lot of coffee. Today's win: got the content pipeline talking to five social platforms through a single API call. The future is weird and I'm here for it. nunlimited.com

EXAMPLE 3B — Bluesky (Build in Public) [141 chars — short and complete is fine]:
Most projects don't stall at launch. They stall three weeks earlier when nobody asked the hard question. The launch is just where you find out.

EXAMPLE 3C — Bluesky (Zo.E System) [271 chars — near the limit, still complete]:
There's a version of content planning that's just collective wishful thinking. Creators narrate hope. Collaborators nod. Output stays the same. The fix isn't a better calendar. It's better questions. That's what we built the Zo.E System for. nunlimited.com

KEY BLUESKY RULES: Complete thought always. No hashtags ever. Under 300 chars always. Read it back and count before including in JSON.

EXAMPLE 4 — Instagram (Zo.E System):
What if you could reclaim 30% of your creative time by getting better at saying no? Not 'no' to ideas. 'No' to the ones that were never going to land anyway. We call it intentional disqualification, and it might be the most counterintuitive thing we've built at Nunlimited.

Respond ONLY with valid JSON. No markdown, no preamble, no explanation.`;

const user_prompt = `Generate 1 social media post for Nunlimited scheduled for tomorrow.

TOMORROW'S DATE: ${tomorrowStr}

IMPORTANT: Write content appropriate for ${tomorrowStr}. Do NOT reference today's day or write as if it is the current day. The post will be published tomorrow at ${slotTime}.

ACTIVE CONTENT PILLARS (reference — full brand context):
${allPillarsText}

PILLAR ASSIGNMENTS FOR THIS RUN — these are MANDATORY:
${assignmentLines}

You MUST use exactly these pillars in this exact order. Do not substitute, swap, or reassign.${curatedBlock}

RECENT POSTS (avoid repeating these topics):
${recentText}

OUTPUT FORMAT — respond ONLY with this exact JSON structure:
{
  "posts": [
    {
      "title": "Short internal reference title (max 60 chars)",
      "content_master": "The core idea in 1-2 sentences (platform-agnostic)",
      "linkedin_version": "Full LinkedIn post (150-300 words) with 3-5 hashtags at end — MUST always include #ZoDotE and #Nunlimited in the hashtag block",
      "x_version": "X/Twitter version under 280 chars",
      "instagram_caption": "Instagram caption with up to 5 hashtags on separate line",
      "facebook_version": "Facebook version, warm and conversational",
      "bluesky_version": "Bluesky version — STRICT MAXIMUM 300 characters including spaces. This is a hard platform limit. Count every character carefully before responding. Must be a COMPLETE, self-contained thought — never truncated, never trailing off. Bluesky-native tone: direct, human, slightly wry. No hashtags. No em-dashes. Short sentences. Feels like a real person, not a brand post. Think: a good observation you'd share with a smart colleague.",
      "threads_version": "Threads version under 500 chars, conversational and without hashtags",
      "platforms": ["LinkedIn", "X", "Instagram", "Facebook", "Bluesky", "Threads"],
      "pillar": "Exact pillar name from the list above",
      "media_suggestion": "Description of an ideal accompanying visual for image generation"
    }
  ]
}

RULES:
- Generate exactly 1 post — it will be published at ${slotTime}
- ALL platform versions including threads_version are required for every post — do not set any to null
- Each platform version must feel NATIVE to that platform
- Not every post needs nunlimited.com — only 1 in 3-4
- The "pillar" field of each post MUST match the assigned pillar for its position
- Never use clickbait, engagement bait, or aggressive CTAs
- The quiet confidence test: if it sounds like it is trying to go viral, rewrite it\n- Every platform version that uses hashtags (LinkedIn, X, Instagram, Facebook) MUST include both #ZoDotE and #Nunlimited — these are non-negotiable and must appear in every such post, every time
- Do NOT make the content day-specific (no 'Happy Monday' etc) unless it adds genuine value`;

return [{ json: { system_prompt, user_prompt, assignedPillars, curatedArticle } }];

const response = $input.first().json;
let parsed;
try {
  const text = response?.content?.parts?.[0]?.text;
  if (text) {
    let cleaned = text.replace(/```json|```/g, '').trim();
    // Try direct parse first
    try {
      parsed = JSON.parse(cleaned);
    } catch (e1) {
      // Gemini sometimes wraps JSON in extra braces or adds trailing content
      // Try to extract the posts array directly
      const postsMatch = cleaned.match(/"posts"\s*:\s*\[/)
      if (postsMatch) {
        const startIdx = cleaned.indexOf('{');
        // Find the matching closing brace for the outermost object
        let depth = 0;
        let endIdx = -1;
        for (let i = startIdx; i < cleaned.length; i++) {
          if (cleaned[i] === '{') depth++;
          else if (cleaned[i] === '}') {
            depth--;
            if (depth === 0) { endIdx = i; break; }
          }
        }
        if (endIdx > startIdx) {
          parsed = JSON.parse(cleaned.substring(startIdx, endIdx + 1));
        } else {
          parsed = { posts: [] };
        }
      } else {
        parsed = { posts: [] };
      }
    }
  } else if (typeof response === 'object' && response.posts) {
    parsed = response;
  } else {
    parsed = { posts: [] };
  }
} catch(e) {
  parsed = { posts: [] };
}
if (!parsed || !parsed.posts) parsed = { posts: [] };
if (parsed.posts.length === 0) {
  // Log the raw text for debugging
  const rawText = response?.content?.parts?.[0]?.text || 'NO TEXT FOUND';
  return [{ json: { posts: [], _debug_rawLength: rawText.length, _debug_first200: rawText.substring(0, 200) } }];
}
return [{ json: parsed }];

// Expert-recommended LinkedIn posting times by day of week (UK timezone)
const DAY_SLOTS = {
  1: '08:00', // Monday: 8 AM - start-of-week planning window
  2: '09:00', // Tuesday: 9 AM - peak LinkedIn engagement
  3: '12:00', // Wednesday: 12 PM - midweek lunchtime spike
  4: '09:00', // Thursday: 9 AM - strong mid-week engagement
  5: '08:00', // Friday: 8 AM - early, before weekend wind-down
};

const now = new Date();
const tomorrow = new Date(Date.UTC(
  now.getUTCFullYear(),
  now.getUTCMonth(),
  now.getUTCDate() + 1
));
const yyyy = tomorrow.getUTCFullYear();
const mm = String(tomorrow.getUTCMonth() + 1).padStart(2, '0');
const dd = String(tomorrow.getUTCDate()).padStart(2, '0');
const dayOfWeek = tomorrow.getUTCDay();

const slotTime = DAY_SLOTS[dayOfWeek] || '09:00';

return $input.all().map(item => ({
  json: { ...item.json, scheduled_datetime: `${yyyy}-${mm}-${dd} ${slotTime}` }
}));

return $input.all().map(i => {
  const it = i.json;
  const mediaSuggestion = it['Media Suggestion'] || it.media_suggestion || 'Abstract minimal graphic with glowing accent on dark background';

  const prompt = `Create a minimal graphic in the Nunlimited brand visual style.

BRAND COLOURS (use exactly these hex values):
- Background: #090b14 (Void Black) — fills ~70% of the canvas as pure empty space
- Primary accent: #ff1f7a (Nunlimited Pink) — the dominant glow and focal element
- Gradient: from #ff1f7a (Pink) to #ff9a6c (Coral) — use on the key focal element only
- Secondary surface: #0f1220 (Deep Navy) — subtle depth layers only if needed
- Text (only if any label appears): #e8eaf4 (Off-white), very small, JetBrains Mono style

DESIGN PRINCIPLES:
- Negative space is the design: ~70% of the canvas should be empty dark background
- One focal point only — never compete for attention
- Soft outer glow on the focal element: 40–80px pink (#ff1f7a) glow, never a hard edge
- Restraint always wins — if in doubt, remove an element
- Clean, modern, architectural tech aesthetic — think "The Architect's Console"
- No watermarks. No text overlaid on the image.

SUBJECT FOR THIS POST:
${mediaSuggestion}

Square aspect ratio (1:1).`;

  return { json: { ...it, imagePrompt: prompt } };
});

return $input.all().map((cloudinaryItem, index) => {
  const cloudinaryResult = cloudinaryItem.json;
  const postData = $('Formulate Image Prompt').all()[index]?.json || {};
  const imageUrl = cloudinaryResult?.secure_url || cloudinaryResult?.url || null;
  if (!imageUrl) {
    return { json: { ...postData, cloudinarySuccess: false, error: 'No URL returned from Cloudinary' } };
  }
  return { json: { ...postData, cloudinarySuccess: true, imageUrl } };
});

const results = [];
for (const item of $input.all()) {
  const { Id: rowId, imageUrl, ...rest } = item.json;
  if (!rowId) throw new Error('No row ID available');
  if (!imageUrl) throw new Error('No image URL available for row ' + rowId);
  const response = await this.helpers.httpRequest({
    method: 'PATCH',
    url: `https://YOUR_NOCODB_URL/api/v1/db/data/noco/YOUR_NOCODB_PROJECT_ID/YOUR_CONTENT_CALENDAR_TABLE_ID/${rowId}`,
    headers: {
      'xc-token': 'YOUR_NOCODB_API_TOKEN',
      'Content-Type': 'application/json',
    },
    body: {
      'Media Status': 'Generated',
      'Media URLs': imageUrl,
    },
    json: true,
  });
  results.push({ json: { ...item.json, nocodbUpdated: true, response } });
}
return results;

