const items = $input.all();
const hasRealData = items && items.length > 0 && items[0].json && !items[0].json.error && items[0].json['Article Title'];
if (!hasRealData) {
  return [{ json: { _empty: true } }];
}
return items;

// === Assign Pillars (Bresenham weighted round-robin) ===
// CRITICAL: Deduplicate NocoDB data — returnAll produces duplicate rows

const rawPillars = $('Get Content Pillars').all().map(i => i.json);
const seenTitles = new Set();
const pillarsData = [];
for (const p of rawPillars) {
  if (p.Title && !seenTitles.has(p.Title)) {
    seenTitles.add(p.Title);
    pillarsData.push(p);
  }
}

const recentData = $('Validate Recent Posts').all().filter(i => !i.json._empty).map(i => i.json);

// Deduplicate post count by Id
const countData = $('Calculate Post Totals').all();
const seenIds = new Set();
let totalPosts = 0;
for (const item of countData) {
  const id = item.json?.Id;
  if (id && !seenIds.has(id)) {
    seenIds.add(id);
    totalPosts++;
  }
}
if (totalPosts === 0) totalPosts = recentData.length;

const EPOCH_OFFSET = 65;
const bresenhamRun = Math.max(0, Math.floor((totalPosts - EPOCH_OFFSET) / 3));

function parseFrequency(freqText) {
  if (!freqText) return 0;
  const txt = String(freqText).toLowerCase().trim();
  if (txt.includes('as needed')) return 0;
  const rangeMatch = txt.match(/(\d+)\s*-\s*(\d+)\s*x\s*\/\s*week/);
  if (rangeMatch) return (parseInt(rangeMatch[1]) + parseInt(rangeMatch[2])) / 2;
  const singleMatch = txt.match(/(\d+(?:\.\d+)?)\s*x\s*\/\s*week/);
  if (singleMatch) return parseFloat(singleMatch[1]);
  return 0;
}

const pillars = pillarsData
  .map(p => ({ title: p.Title, weight: parseFrequency(p['Target Frequency']) }))
  .filter(p => p.weight > 0);

const POSTS_PER_RUN = 1;
const totalWeight = pillars.reduce((s, p) => s + p.weight, 0);
const dailyShare = {};
pillars.forEach(p => { dailyShare[p.title] = (p.weight / totalWeight) * POSTS_PER_RUN; });

const credits = {};
pillars.forEach(p => { credits[p.title] = 0; });

for (let run = 0; run < bresenhamRun; run++) {
  pillars.forEach(p => { credits[p.title] += dailyShare[p.title]; });
  const sorted = pillars.slice().sort((a, b) => credits[b.title] - credits[a.title]);
  sorted.slice(0, 1).forEach(p => { credits[p.title] -= 1; });
}

pillars.forEach(p => { credits[p.title] += dailyShare[p.title]; });
const sorted = pillars.slice().sort((a, b) => credits[b.title] - credits[a.title]);
const assignedPillars = sorted.slice(0, 1).map(p => p.title);

const curatedIndex = assignedPillars.indexOf('Curated & Commentary');
let curatedArticle = null;

if (curatedIndex >= 0) {
  const candidateData = $('Retrieve Curated Post').all();
  if (candidateData.length > 0 && candidateData[0].json && !candidateData[0].json._empty) {
    const c = candidateData[0].json;
    curatedArticle = {
      articleTitle: c['Article Title'] || '',
      url: c.URL || '',
      source: c.Source || '',
      author: c.Author || '',
      excerpt: c.Excerpt || '',
      suggestedAngle: c['Suggested Angle'] || '',
      queueRowId: c.Id || null,
    };
  } else {
    const substitute = sorted.find((p, i) => i >= 3);
    if (substitute) {
      assignedPillars[curatedIndex] = substitute.title;
    }
    curatedArticle = { _empty: true };
  }
}

const allPillarsText = pillarsData.map(item => {
  return 'PILLAR: ' + item.Title +
    '\nDESCRIPTION: ' + (item.Description || '') +
    '\nEXAMPLE TOPICS: ' + (item['Example Topics'] || '') +
    '\nFREQUENCY: ' + (item['Target Frequency'] || '');
}).join('\n\n');

const assignmentLines = assignedPillars.map((p, idx) =>
  'Post ' + (idx + 1) + ' MUST be the \"' + p + '\" pillar.'
).join('\n');

const recentText = recentData.length > 0
  ? recentData.slice(0, 15).map(item => '- ' + (item.Title || 'untitled') + ' [' + (item.Pillar || '?') + ']').join('\n')
  : 'No recent posts yet.';

return [{
  json: {
    assignedPillars,
    curatedArticle,
    curatedQueueEmpty: curatedArticle && curatedArticle._empty,
    allPillarsText,
    assignmentLines,
    recentText,
    bresenhamRun,
    totalPostsDeduplicated: totalPosts,
    pillarCountRaw: rawPillars.length,
    pillarCountDeduplicated: pillarsData.length,
    creditState: Object.fromEntries(pillars.map(p => [p.title, credits[p.title].toFixed(3)])),
  }
}];

const items = $input.all();
const seenIds = new Set();
for (const item of items) {
  const id = item.json?.Id;
  if (id) seenIds.add(id);
}
return [{ json: { totalPosts: seenIds.size } }];

// Gate: skip generation if tomorrow already has an Approved post scheduled
const now = new Date();
const tomorrow = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1));
const yyyy = tomorrow.getUTCFullYear();
const mm = String(tomorrow.getUTCMonth() + 1).padStart(2, '0');
const dd = String(tomorrow.getUTCDate()).padStart(2, '0');
const tomorrowDate = `${yyyy}-${mm}-${dd}`;

// Build URL directly — avoids qs double-encoding the space in "Scheduled Datetime".
// Use gte/lte instead of like — NocoDB does not support like on datetime fields (422).
const whereClause = `(Status,eq,Approved)~and(Scheduled%20Datetime,gte,${tomorrowDate}%2000:00:00)~and(Scheduled%20Datetime,lte,${tomorrowDate}%2023:59:59)`;

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://YOUR_NOCODB_URL/api/v1/db/data/noco/YOUR_NOCODB_PROJECT_ID/YOUR_CONTENT_CALENDAR_TABLE_ID?where=${whereClause}&fields=Id,Title&limit=1`,
  headers: { 'xc-token': 'YOUR_NOCODB_API_TOKEN' },
  json: true,
});

const existing = response?.list || [];
if (existing.length > 0) {
  // Tomorrow already has content scheduled — skip generation silently
  return [];
}

// Nothing scheduled for tomorrow — proceed with generation
return [{ json: { proceed: true, date: tomorrowDate } }];
